class Solution:
    def countPairs(self, nums: List[int], low: int, high: int) -> int:
        count = 0
        for i in range(len(nums)):
            for j in range(i + 1, len(nums)):
                if low <= nums[i] ^ nums[j] <= high:
                    count += 1
        return count
